SPARQL Query:
PREFIX pko: <https://w3id.org/pko#> 
PREFIX pko-aud: <https://w3id.org/pko/audit#> 
PREFIX prov: <http://www.w3.org/ns/prov#> 

SELECT *
WHERE {
?procedureExecution a pko:ProcedureExecution ;
prov:wasAssociatedWith ?auditableSystem .
?auditableSystem a pko-aud:AuditableSystem .
}

PREFIX pko-aud: <https://w3id.org/pko/audit#> 

SELECT *
WHERE {
?auditableProcedure a pko-aud:AuditableProcedure ;
pko-aud:hasAuditableSystem ?auditableSystem .
}

PREFIX pko: <https://w3id.org/pko#> 
PREFIX pko-aud: <https://w3id.org/pko/audit#> 
PREFIX prov: <http://www.w3.org/ns/prov#> 

SELECT *
WHERE {
?procedureExecution a pko:ProcedureExecution ;
prov:wasAssociatedWith ?auditableSystem .
?auditableSystem a pko-aud:AuditableSystem .
?auditBundle a pko-aud:AuditBundle ;
prov:wasGeneratedBy ?procedureExecution ;
prov:wasAttributedTo ?auditableSystem .
}

PREFIX pko: <https://w3id.org/pko#> 
PREFIX pko-aud: <https://w3id.org/pko/audit#> 
PREFIX dct: <http://purl.org/dc/terms/> 

SELECT *
WHERE {
?auditBundle a pko-aud:AuditBundle ;
dct:references ?stepExecution .
?stepExecution a pko:StepExecution .
}

PREFIX pko-aud: <https://w3id.org/pko/audit#> 
PREFIX prov: <http://www.w3.org/ns/prov#> 

SELECT *
WHERE {
?auditBundle a pko-aud:AuditBundle ;
prov:generatedAtTime ?time .
}

PREFIX pko: <https://w3id.org/pko#> 
PREFIX pko-aud: <https://w3id.org/pko/audit#> 
PREFIX prov: <http://www.w3.org/ns/prov#> 

SELECT *
WHERE {
?procedureExecution a pko:ProcedureExecution ;
prov:wasAssociatedWith ?auditableSystem .
?auditableSystem a pko-aud:AuditableSystem .
?auditBundle a pko-aud:AuditBundle ;
prov:wasGeneratedBy ?procedureExecution ;
prov:wasAttributedTo ?auditableSystem ;
pko-aud:wasCollectedBy ?auditService .
?auditService a pko-aud:AuditService .
}

PREFIX pko-aud: <https://w3id.org/pko/audit#> 

SELECT *
WHERE {
?auditableSystem a pko-aud:AuditableSystem ;
pko-aud:hasService ?auditService .
}
